-- تحديث بيانات المؤلف أسامة مسلم مع تعريف طويل وصورة جديدة
UPDATE public.authors 
SET 
  bio = 'د. أسامة مسلم كاتب وباحث في الفكر الإسلامي المعاصر، حاصل على الدكتوراه في الدراسات الإسلامية من جامعة الأزهر الشريف. له العديد من المؤلفات والبحوث في مجال الفكر الإسلامي والتربية والدعوة، ويعتبر من أبرز المفكرين المعاصرين في العالم العربي.

تميز د. أسامة مسلم بأسلوبه الواضح والمبسط في الكتابة، مما جعل أعماله محط اهتمام القراء من مختلف الفئات العمرية والثقافية. يركز في كتاباته على ربط التراث الإسلامي بالواقع المعاصر، ويسعى إلى تقديم رؤية متوازنة للفكر الإسلامي تجمع بين الأصالة والمعاصرة.

من أشهر أعماله: "في ظلال القرآن العملي"، "مناهج التفكير الإسلامي"، "التربية الإيمانية في الإسلام"، و"الدعوة في العصر الحديث". كما شارك في العديد من المؤتمرات العلمية والندوات الفكرية على المستوى المحلي والدولي، وله مساهمات فعالة في البرامج الإذاعية والتلفزيونية التي تعنى بالشؤون الإسلامية والفكرية.',
  avatar_url = 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTDE5mkG_XzNZ2u5_PdKLjXR0F2-HKTcNhgzC-li-xnpQ&s=10'
WHERE name = 'أسامة مسلم';